import java.util.*;
class Main {
    static class DSU {
        int[] parent;
        int[] size;
        public DSU(int n) {
            parent = new int[n + 1];
            size = new int[n + 1];
            for (int i = 1; i <= n; i++) {
                parent[i] = i;
                size[i] = 1;
            }
        }
        public int findParent(int v) {
            if (parent[v] == v)
                return v;
            return parent[v] = findParent(parent[v]);
        }
        public void mergeSet(int a, int b, int[] s) {
            a = findParent(a);
            b = findParent(b);
            if (s[b] > s[a]) {
                parent[a] = b;
            } else if (s[a] > s[b]) {
                parent[b] = a;
            }
        }
        public boolean sameSet(int a, int b) {
            return findParent(a) == findParent(b);
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int[] s = new int[n + 1];
            for (int i = 1; i <= n; i++) {
                s[i] = scanner.nextInt();
            }
            DSU d = new DSU(n);
            int q = scanner.nextInt();
            for (int i = 0; i < q; i++) {
                int type = scanner.nextInt();
                if (type == 0) {
